class Solution {
public:
bool findDuplicate(vector<int>& nums) {
	unordered_set<int> seen;
	for (int num : nums) {
		if (seen.find(num) != seen.end()) return num;
		seen.insert(num);
	}
	return -1;
}
};
int main() {
	int n;
	cin >> n;
	vector<int> nums(n);
	for (int i = 0; i < n; i++) {
		cin >> nums[i];
	}
	Solution solution;
	int result = solution.findDuplicate(nums);
	if (result != -1) {
		cout << result << endl;
	} else {
		cout << -1 << endl;
	}
	return 0;
}

