		int result = solution.findDuplicate(nums);
		if (result != -1) {
			System.out.println(result);
		} else {
			System.out.println(-1);
		}
	}
}
// Solution
class Solution {
	public int findDuplicate(int[] nums) {
		HashSet<Integer> seen = new HashSet<>();
		for (int num : nums) {
			if (seen.contains(num)) return num;
			seen.add(num);
		}
		return -1;
	}
}

